 1→import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';
 2→
 3→const corsHeaders = {
 4→  'Access-Control-Allow-Origin': '*',
 5→  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
 6→};
 7→
 8→Deno.serve(async (req) => {
 9→  if (req.method === 'OPTIONS') return new Response('ok', { headers: corsHeaders });
10→
11→  try {
12→    const supabase = createClient(
13→      Deno.env.get('SUPABASE_URL')!,
14→      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!
15→    );
16→
17→    const authHeader = req.headers.get('Authorization');
18→    if (!authHeader) return new Response(JSON.stringify({ error: 'No auth' }), { status: 401, headers: corsHeaders });
19→
20→    const { data: { user } } = await supabase.auth.getUser(authHeader.replace('Bearer ', ''));
21→    if (!user) return new Response(JSON.stringify({ error: 'Unauthorized' }), { status: 401, headers: corsHeaders });
22→
23→    const { card_id, reward_id } = await req.json();
24→    if (!card_id || !reward_id) return new Response(JSON.stringify({ error: 'Missing card_id or reward_id' }), { status: 400, headers: corsHeaders });
25→
26→    const { data: card } = await supabase.from('customer_cards').select('*, loyalty_programs(type)').eq('id', card_id).eq('customer_id', user.id).single();
27→    if (!card) return new Response(JSON.stringify({ error: 'Card not found' }), { status: 404, headers: corsHeaders });
28→
29→    const { data: reward } = await supabase.from('rewards').select('*').eq('id', reward_id).eq('is_active', true).single();
30→    if (!reward) return new Response(JSON.stringify({ error: 'Reward not found' }), { status: 404, headers: corsHeaders });
31→
32→    const programType = card.loyalty_programs.type;
33→    if (programType === 'stamp' && card.current_stamps < (reward.stamps_required || 0)) {
34→      return new Response(JSON.stringify({ error: 'Not enough stamps' }), { status: 400, headers: corsHeaders });
35→    }
36→    if (programType === 'points' && card.current_points < (reward.points_cost || 0)) {
37→      return new Response(JSON.stringify({ error: 'Not enough points' }), { status: 400, headers: corsHeaders });
38→    }
39→
40→    if (programType === 'stamp') {
41→      await supabase.from('customer_cards').update({
42→        current_stamps: card.current_stamps - (reward.stamps_required || 0),
43→        last_activity: new Date().toISOString(),
44→      }).eq('id', card.id);
45→    } else {
46→      await supabase.from('customer_cards').update({
47→        current_points: card.current_points - (reward.points_cost || 0),
48→        last_activity: new Date().toISOString(),
49→      }).eq('id', card.id);
50→    }
51→
52→    await supabase.from('transactions').insert({
53→      card_id: card.id,
54→      type: 'reward_redeem',
55→      value: reward.stamps_required || reward.points_cost || 0,
56→      validated_by: 'manual',
57→    });
58→
59→    return new Response(JSON.stringify({
60→      success: true,
61→      reward_name: reward.name,
62→      discount_type: reward.discount_type,
63→      discount_value: reward.discount_value,
64→    }), { status: 200, headers: { ...corsHeaders, 'Content-Type': 'application/json' } });
65→
66→  } catch (err) {
67→    return new Response(JSON.stringify({ error: (err as Error).message }), { status: 500, headers: corsHeaders });
68→  }
69→});
